                              .filter(s => s.trim() !== '');

if (sentences.length === 0 && fullResponse.trim() !== '') {
  sentences.push(fullResponse.trim());
}

// CRUCIAL: Criamos um array de OBJETOS, onde cada um tem uma chave "text".
item.json.messagesToSend = sentences.map(sentence => ({ text: sentence.trim() }));

// Retorna o item único com o array dentro.
return [item];

