const item = items[0];
const fullResponse = $('OrganizaResposta').first().json.output?.trim() || "";

// Divide o texto em frases (strings individuais)
const sentences = fullResponse
  .split(/(?<=[.?!])\s+|\n\s*\n|\n(?=[A-Z])/)
  .map(s => s.trim())
  .filter(s => s.length > 0);

// Caso não tenha divisões válidas, mantém o texto inteiro
item.json.messagesToSend = sentences.length > 0 ? sentences : [fullResponse];

return [item];

const item = items[0];
let atendentes = $('Code in JavaScript2').item.json.numerosAtendentes; // fallback caso venha vazio

// Garante que seja array
if (!Array.isArray(atendentes)) {
  atendentes = [atendentes];
}

// Cria uma lista de objetos para o SplitInBatches
return atendentes.map(numero => ({
  json: {
    numero,
    mensagem: `Olá, tudo bem? Veio te notificar para assumir a conversa no NKW FLOW, segue o número: ${ $('Code in JavaScript2').item.json.contatoNumero }`
  }
}));

let text = $json.output;

// Garante que o valor é uma string
if (typeof text !== 'string') {
  return [{ json: { output: text } }];
}

// Remove blocos de código e espaços extras
text = text.replace(/```json|```/g, '').trim();

// Tenta fazer o parse do JSON
let parsed;
try {
  parsed = JSON.parse(text);
} catch (e) {
  parsed = {
    resposta: "Erro ao interpretar resposta da IA.",
    isChamaAtendente: true
  };
}

// Retorna objeto limpo
return [{ json: { output: parsed } }];

const item = items[0];
let events = $('ChegouEvento').first().json.body.events; 

// Garante que seja array
if (!Array.isArray(events)) {
  events = [events];
}

// Cria uma lista de objetos para o SplitInBatches
return events.map(event => ({
  json: {
    event
  }
}));

// Pega todos os itens da entrada como um array
const allItems = $input.all();

// Pega o JSON do *primeiro* item para usarmos como base
// para os dados "estáticos" (IdAssinante, promptAgente, etc.)
const firstItem = $input.first().json;

// --- 1. Concatenação dos Campos Dinâmicos ---

// Mapeia todos os 'mensagemTexto', remove nulos/vazios e junta com nova linha
const mensagensTexto = allItems
  .map(item => item.json.mensagemTexto)
  .filter(Boolean) // 'Boolean' remove valores nulos, vazios, undefined
  .join('\n');

// Mapeia todos os 'TextoImagem', remove nulos/vazios e junta com nova linha
const textosImagem = allItems
  .map(item => item.json.TextoImagem)
  .filter(Boolean)
  .join('\n');

// Mapeia todos os 'TextoAudio', remove nulos/vazios e junta com nova linha
const textosAudio = allItems
  .map(item => item.json.TextoAudio)
  .filter(Boolean)
  .join('\n');

// --- 2. Montagem do Objeto de Saída ---

// Retorna um novo objeto.
// Incluímos os campos estáticos do 'firstItem' um por um
// e depois adicionamos os nossos campos concatenados.
return {
  // Dados estáticos do primeiro item:
  IdAssinante: firstItem.IdAssinante,
  tipoMensagem: firstItem.tipoMensagem,
  promptAgente: firstItem.promptAgente,
  numerosAtendentes: firstItem.numerosAtendentes,
  chatId: firstItem.chatId,
  contatoNumero: firstItem.contatoNumero,
  connectionId: firstItem.connectionId,
  mensagemCitada: firstItem.mensagemCitada,

  // Campos dinâmicos (concatenados):
  mensagemTexto: mensagensTexto,
  TextoImagem: textosImagem,
  TextoAudio: textosAudio
};
